
'use client';

import React, { useEffect, useState } from 'react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { ScrollArea } from '@/components/ui/scroll-area';
import { User, Edit2, Trash, Mail, UserCheck, UserX } from 'lucide-react';
// import axios from 'axios';
import Link from 'next/link';

interface UserType {
  id: string;
  name: string;
  email: string;
  role: 'admin' | 'customer';
}

export default function UsersPage() {
  const [users, setUsers] = useState<UserType[]>([]);

  useEffect(() => {
    // 🟢 Dummy users data
    const dummyUsers: UserType[] = [
      { id: 'U-201', name: 'Priya Sharma', email: 'priya@example.com', role: 'customer' },
      { id: 'U-202', name: 'Amit Verma', email: 'amit@example.com', role: 'customer' },
      { id: 'U-203', name: 'Admin User', email: 'admin@example.com', role: 'admin' },
    ];
    setUsers(dummyUsers);

    // 🟢 Replace with API call
    // const token = localStorage.getItem('token');
    // axios.get('/api/users', { headers: { Authorization: `Bearer ${token}` } })
    //   .then(res => setUsers(res.data));
  }, []);

  const handleDelete = (id: string) => {
    if (!confirm('Are you sure you want to delete this user?')) return;
    setUsers(prev => prev.filter(u => u.id !== id));

    // 🟢 Replace with API call
    // axios.delete(`/api/users/${id}`, { withCredentials: true });
  };

  return (
    <div className="p-6 space-y-6">
      <h1 className="text-2xl font-bold mb-4">Users</h1>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
        {users.map(user => (
          <Card key={user.id} className="hover:shadow-md transition">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <User size={20} />
                {user.name}
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-2">
              <p className="flex items-center gap-1"><Mail size={14} /> {user.email}</p>
              <p className="flex items-center gap-1">
                {user.role === 'admin' ? <UserCheck size={14} /> : <UserX size={14} />} {user.role}
              </p>
              <div className="flex justify-end gap-2 mt-3">
                <Link href={`/admin/users/${user.id}`}>
                  <Button size="sm" className="bg-blue-600 hover:bg-blue-700 text-white">
                    <Edit2 size={14} className="mr-1" /> View
                  </Button>
                </Link>
                <Button size="sm" className="bg-red-600 hover:bg-red-700 text-white" onClick={() => handleDelete(user.id)}>
                  <Trash size={14} className="mr-1" /> Delete
                </Button>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>
    </div>
  );
}
